const title = ($json['Title'] || '').toLowerCase();
const manualTemplate = ($json['Template Type'] || '').trim();

// Extract first name from full name
const firstName = ($json['Name'] || '').split(' ')[0].trim();

const DOC_IDS = {
  recruiter:      '1HLxoep1-pHOsEILnbN5Wo05rttSzeXfFAoZbkgxE2vw',
  hiring_manager: '1bgMDkgTz00kPX7YYvCIFPp7zdgRzuT-oG7_nybgJd_A',
  founder:        '1ovT0WXGH4rxm4FCCSRB0Lfp6GZWdtks7_ajx9iDMo2M',
  peer_referral:  '19pu_EIVp0Swg23xSdeKW9HtsN-EfIViakyt5hyTTYoU',
  generic:        '19pu_EIVp0Swg23xSdeKW9HtsN-EfIViakyt5hyTTYoU'
};

let template;
if (manualTemplate) {
  template = manualTemplate.toLowerCase();
} else if (/recruiter|talent|\bhr\b|human resources/i.test(title)) {
  template = 'recruiter';
} else if (/manager|lead|head|director|\bvp\b|vice president/i.test(title)) {
  template = 'hiring_manager';
} else if (/founder|ceo|co-founder|owner|president/i.test(title)) {
  template = 'founder';
} else if (/data scientist|ml engineer|machine learning|ai engineer|research|analyst|engineer|developer/i.test(title)) {
  template = 'peer_referral';
} else {
  template = 'generic';
}

return { ...$json, resolvedTemplate: template, docId: DOC_IDS[template], firstName };

const text = ($json.content || '').trim();

if (!text) {
  throw new Error('Google Doc is empty. Make sure the doc has content.');
}

const leadData = $('Determine Template').item.json;
return { ...leadData, templateContent: text };

// Get raw HTML from the fetch response
const html = ($json.data || $json.body || '').toString();

// Strip scripts, styles, nav, footer, comments, and all tags
let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 4000);

// Carry all lead + template data forward with company research
const leadData = $('Extract Doc Text').item.json;
return { ...leadData, companyResearch: text };

const firstName = $json.firstName || '';
const name = $json.Name || '';
const title = $json.Title || '';
const company = $json.Company || '';
const templateType = $json.resolvedTemplate || 'generic';
const companyUrl = $json['Company URL'] || 'company website';
const companyResearch = $json.companyResearch || 'No research available — use company name and lead title context only.';
const templateContent = $json.templateContent || '';

const prompt = `You are personalizing a cold outreach email for Bhavik Chopra, a data scientist, AI engineer, and developer relations lead based in New York.

LEAD:
- First Name: ${firstName}
- Full Name: ${name}
- Title: ${title}
- Company: ${company}
- Template Type: ${templateType}

COMPANY RESEARCH (scraped from ${companyUrl}):
${companyResearch}

EMAIL TEMPLATE:
${templateContent}

FIXED VALUES — insert these exactly where indicated, do not rephrase:
- {{PROOF_POINT}} = architected a production GenAI system cutting intake-to-routing time by 75% with zero critical compliance incidents since deployment
- Build / Lead / Communicate bullets = copy word for word from the template
- LinkedIn URL = https://www.linkedin.com/in/jbhavik70/
- Resume URL = https://docs.google.com/document/d/15lZ5XpKPBBOuABvEvwb6-cXnLg9KhROLBBuwz3_JtZU/edit?usp=sharing

YOUR JOB:
Replace ONLY the {{PLACEHOLDER}} markers using the instructions below. Copy every other word exactly as written in the template.

PLACEHOLDERS:
- {{FIRST_NAME}} = use the lead first name
- {{COMPANY}} = use the company name
- {{SUBJECT_TAG}} = short specific tag based on template type and company research:
  generic: one specific thing you admire about what they have built or shipped
  hiring_manager: one specific thing about their team, stack, or recent technical work
  founder: the specific bet or move they are making (raise, launch, product direction)
  recruiter: infer role area from company research context (e.g. your AI hiring or Senior DS roles)
- {{COMPANY_SPECIFIC_REASON}} (generic only) = specific project, product, or design from research
- {{HONEST_TAKE}} (generic only) = one honest sentence on why it caught your eye
- {{COMPANY_SPECIFIC_PROJECT}} (hiring_manager only) = specific recent project, launch, or technical decision
- {{TECHNICAL_ANGLE}} (hiring_manager only) = one sentence on the technical or operational angle
- {{PROOF_POINT}} (hiring_manager only) = use the fixed value above
- {{RECENT_MOVE}} (founder only) = specific recent move from research (launch, raise, public take, product decision)
- {{REAL_TAKE}} (founder only) = one real take on it, not a congratulations
- {{PERSONALIZATION_LINE}} (founder only) = one line tied to what they are building or a recent signal
- {{COMPANY_HOOK}} (recruiter only) = one specific line on why this company or their hiring stood out

RULES:
1. Fill ONLY {{PLACEHOLDER}} markers — copy all other text exactly as written
2. Use company research to fill placeholders — do not invent facts not found in the research
3. If research is empty or unclear, write a plausible honest observation using company name and lead title
4. Each paragraph must be ONE continuous line — no line breaks inside a paragraph
5. Separate paragraphs with exactly two newlines
6. Do NOT use hyphens, em dashes, or bullet points anywhere in the email — write in plain flowing sentences like a human would
7. Return ONLY valid JSON, no markdown, no code fences:
{"subject": "...", "body": "..."}`;

return { ...$json, claudePrompt: prompt };

// Extract Claude's response text
const raw = $json.content?.[0]?.text || '';

// Strip markdown code fences if Claude added them
const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude returned invalid JSON: ' + cleaned);
}

const body = (parsed.body || '').trim();

// Split on any newline(s) into paragraphs
const paragraphs = body
  .split(/\n+/)
  .map(p => p.trim())
  .filter(p => p.length > 0);

// Build HTML — with special formatting rules
const htmlParts = paragraphs.map(p => {
  // Bold the recruiter snapshot labels
  p = p
    .replace(/^Build:/, '<strong>Build:</strong>')
    .replace(/^Lead:/, '<strong>Lead:</strong>')
    .replace(/^Communicate:/, '<strong>Communicate:</strong>');

  // Convert LinkedIn URL to a clean LinkedIn link
  p = p.replace(
    /https:\/\/www\.linkedin\.com\/in\/jbhavik70\//g,
    '<a href="https://www.linkedin.com/in/jbhavik70/">LinkedIn</a>'
  );

  // Convert resume URL to a clean Resume link
  p = p.replace(
    /https:\/\/docs\.google\.com\/document\/d\/15lZ5XpKPBBOuABvEvwb6-cXnLg9KhROLBBuwz3_JtZU\/edit[^\s]*/g,
    '<a href="https://docs.google.com/document/d/15lZ5XpKPBBOuABvEvwb6-cXnLg9KhROLBBuwz3_JtZU/edit?usp=sharing">Resume Link</a>'
  );

  return '<p style="margin:0 0 12px 0;">' + p + '</p>';
});

const htmlBody = htmlParts.join('\n');

const leadData = $('Extract Page Text').item.json;
return { ...leadData, emailSubject: parsed.subject, emailBody: htmlBody };
